// AI Agent'tan gelen ham metni al ve temiz JSON formatına dönüştür
let rawText = items[0].json.output;

// Eğer AI Agent yanıtı tırnak içinde veya markdown bloğunda verdiyse temizle
rawText = rawText.replace(/```json/g, "").replace(/```/g, "").trim();

try {
  const cleanJson = JSON.parse(rawText);
  return [{ json: cleanJson }];
} catch (error) {
  // Olası bir hata durumunda sistemin çökmemesi için güvenli fallback komutu
  return [{ json: { "komut_su": "kapat", "komut_fan": "kapat", "komut_isitici": "kapat" } }];
}
